(window.webpackJsonp=window.webpackJsonp||[]).push([[123],{750:function(n,t){n.exports='\x3c!-- \r\ntitle: 05-中断\r\nsort: \r\n--\x3e \r\n# 中断\r\n\r\n![image-20200904203225205](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20200904203225.png)\r\n\r\n![image-20200904202234877](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20200904202234.png)\r\n\r\n## 外部中断\r\n\r\n```c\r\n#include "reg51.h"\r\n\r\ntypedef unsigned char u8;\r\ntypedef unsigned int u16;\r\n\r\nsbit led=P2^0;\r\nsbit k3=P3^2;\r\n\r\nvoid delay(u16 i)\r\n{\r\n    while(i--);\r\n}\r\n\r\nvoid Int0Init()\r\n{\r\n\tIT0=1;\t// 下降沿触发\r\n\tEX0=1;\t// 打开外部中断\r\n\tEA=1;\t// 打开总中断\r\n}\r\n\r\nvoid main()\r\n{\r\n\tInt0Init();\r\n    while(1);\r\n}\r\n\r\nvoid Int0() interrupt 0\r\n{\r\n\tdelay(1000);\r\n\tif(k3==0)\r\n\t{\r\n\t\tled=~led;\r\n\t}\r\n}\r\n```\r\n\r\n## 定时器\r\n\r\n```c\r\n#include "reg51.h"\r\n\r\ntypedef unsigned char u8;\r\ntypedef unsigned int u16;\r\n\r\nsbit led=P2^0;\r\n\r\nvoid Timer0Init()\r\n{\r\n\tTMOD|=0x01;\r\n\tTH0=0xFC;\r\n\tTL0=0X18;\r\n\tET0=1;\t// 打开中断\r\n\tEA=1;\t// 打开总中断\r\n\tTR0=1;\r\n}\r\n\r\nvoid main()\r\n{\r\n\tTimer0Init();\r\n    while(1);\r\n}\r\n\r\nvoid Time0() interrupt 1\r\n{\r\n\tstatic u16 i;\r\n\tTH0=0xFC;\r\n\tTL0=0X18;\r\n\ti++;\r\n\tif(i==1000)\r\n\t{\r\n\t\ti=0;\r\n\t\tled=~led;\r\n\t}\r\n}\r\n```\r\n\r\n## NE555\r\n\r\n```c\r\n#include "reg51.h"\r\n#define GPIO_DIG P0\r\n\r\ntypedef unsigned char u8;\r\ntypedef unsigned int u16;\r\n\r\nsbit LSA = P2 ^ 2;\r\nsbit LSB = P2 ^ 3;\r\nsbit LSC = P2 ^ 4;\r\n\r\nu8 code smgduan[] = {0x3f, 0x06, 0x5b, 0x4f, 0x66, 0x6d, 0x7d, 0x07, 0x7f,\r\n\t\t\t\t\t 0x6f, 0x77, 0x7c, 0x39, 0x5e, 0x79, 0x71};\r\n\r\nunsigned long TimeCount;\r\nunsigned long Freq;\r\n\r\nu8 DisplayData[8];\r\n\r\nvoid delay(u16 i)\r\n{\r\n\twhile (i--)\r\n\t\t;\r\n}\r\n\r\nvoid DigDisplay()\t// 数码管段选显示\r\n{\r\n\tu8 i;\r\n\tfor (i = 0; i < 8; i++)\r\n\t{\r\n\t\tswitch (i)\r\n\t\t{\r\n\t\tcase 0:\r\n\t\t\tLSA = 0;\r\n\t\t\tLSB = 0;\r\n\t\t\tLSC = 0;\r\n\t\t\tbreak;\r\n\t\tcase 1:\r\n\t\t\tLSA = 1;\r\n\t\t\tLSB = 0;\r\n\t\t\tLSC = 0;\r\n\t\t\tbreak;\r\n\t\tcase 2:\r\n\t\t\tLSA = 0;\r\n\t\t\tLSB = 1;\r\n\t\t\tLSC = 0;\r\n\t\t\tbreak;\r\n\t\tcase 3:\r\n\t\t\tLSA = 1;\r\n\t\t\tLSB = 1;\r\n\t\t\tLSC = 0;\r\n\t\t\tbreak;\r\n\t\tcase 4:\r\n\t\t\tLSA = 0;\r\n\t\t\tLSB = 0;\r\n\t\t\tLSC = 1;\r\n\t\t\tbreak;\r\n\t\tcase 5:\r\n\t\t\tLSA = 1;\r\n\t\t\tLSB = 0;\r\n\t\t\tLSC = 1;\r\n\t\t\tbreak;\r\n\t\tcase 6:\r\n\t\t\tLSA = 0;\r\n\t\t\tLSB = 1;\r\n\t\t\tLSC = 1;\r\n\t\t\tbreak;\r\n\t\tcase 7:\r\n\t\t\tLSA = 1;\r\n\t\t\tLSB = 1;\r\n\t\t\tLSC = 1;\r\n\t\t\tbreak;\r\n\t\t}\r\n\t\tGPIO_DIG = DisplayData[i];\r\n\t\tdelay(100);\r\n\t\tGPIO_DIG = 0x00; // 清零\r\n\t}\r\n}\r\n\r\nvoid TimerConfig()\t// 初始化定时器\r\n{\r\n\tTMOD = 0x51;\t// 设置工作模式\r\n\r\n\tTH0 = 0x3C;\t\t// 计数次数\r\n\tTL0 = 0XB0;\r\n\r\n\tET0 = 1; // 打开中断\r\n\tET1 = 1;\r\n\r\n\tEA = 1; // 打开总中断\r\n\r\n\tTR0 = 1;\r\n\tTR1 = 1;\r\n}\r\n\r\nvoid main()\r\n{\r\n\tTimerConfig();\t// 初始化\r\n\twhile (1)\r\n\t{\r\n\t\tif (TR1 == 0)\r\n\t\t{\r\n\t\t\tFreq = Freq + TL1;\r\n\t\t\tFreq = Freq + (TH1 * 256);\r\n\r\n\t\t\tDisplayData[0] = smgduan[Freq % 1000000 / 100000];\r\n\t\t\tDisplayData[1] = smgduan[Freq % 100000 / 10000];\r\n\t\t\tDisplayData[2] = smgduan[Freq % 10000 / 1000];\r\n\t\t\tDisplayData[3] = smgduan[Freq % 1000 / 100];\r\n\t\t\tDisplayData[4] = smgduan[Freq % 100 / 10];\r\n\t\t\tDisplayData[4] = smgduan[Freq % 10];\r\n\r\n\t\t\tFreq = 0;\r\n\r\n\t\t\tTH1 = 0; \t// 清空寄存器中的值\r\n\t\t\tTL1 = 0;\r\n\r\n\t\t\tTR1 = 1;\r\n\t\t\tTR0 = 1;\r\n\t\t}\r\n\t\tDigDisplay();\r\n\t}\r\n}\r\n\r\nvoid Time0() interrupt 1\t\t\t// 定时器\r\n{\r\n\tTH0 = 0x3C;\r\n\tTL0 = 0XB0;\r\n\tTimeCount++;\r\n\tif (TimeCount == 20)\r\n\t{\r\n\t\tTimeCount = 0;\r\n\t\tTR1 = 0;\r\n\t\tTR0 = 0;\r\n\t}\r\n}\r\n\r\nvoid Timer1() interrupt 3\t\t// 计数器\r\n{\r\n\t// 当计数器到达65536（溢出时），触发中断，则频率+65536\r\n\tFreq += 65536;\r\n}\r\n```\r\n\r\n## 串口\r\n\r\n```c\r\n#include "reg51.h"\r\n\r\ntypedef unsigned char u8;\r\ntypedef unsigned int u16;\r\n\r\nvoid UsartInit()\r\n{\r\n\tTMOD=0x20;\r\n\tTH1=0xF3;\r\n\tTL1=0xF3;\r\n\tPCON=0x80;\r\n\tTR1=1;\r\n\tSCON=0x50;\r\n\tES=1;\r\n\tEA=1;\r\n}\r\n\r\nvoid main()\r\n{\r\n\tUsartInit();\r\n\twhile(1);\r\n}\r\n\r\nvoid Usart() interrupt 4\r\n{\r\n\tu8 receiveData;\r\n\treceiveData=SBUF;\r\n\tRI=0;\r\n\tSBUF=receiveData;\r\n\twhile(!TI);\r\n\tTI=0;\r\n\t\r\n}\r\n```\r\n\r\n'}}]);